const BANNER: &str = r#"
     ____              __  __                        ____  _____
    / __ \____ _____  / /_/ /_  ___  ____  ____     / __ \/ ___/
   / /_/ / __ `/ __ \/ __/ __ \/ _ \/ __ \/ __ \   / / / /\__ \ 
