 /_/    \____/_/ /_/\__/_/ /_/\___/\____/_/ /_/   \____//____/  
 "#;

static BOOTED: Lazy<AtomicBool> = Lazy::new(|| AtomicBool::new(false));

#[no_mangle]
pub fn rust_main(hart_id: usize, dtb: usize) {
    if BOOTED
        .compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst)
        .is_ok()
    {
        // early_init_logging();
        // // platform::init(hart_id, dtb);
        // let platform_info = platform_info_from_dtb(dtb);
        // println!("{:#?}", platform_info);
        // kmm::init();
        // platform::init(hart_id, dtb);
        processor::init(hartid!());
        println!("hart_id : {}", hart_id);
        println!("{}", BANNER);
        println!("[kernel] -------- Boot hart {} start -------- ", hartid!());
        init_device();
        #[cfg(not(feature = "uitest"))]
        fs::init();
        ktime_init();
        knet::config::init();
        trap::init();

        spawn_ktask(async move {
            task::add_initproc().await;
        });
        BOOTED.store(false, Ordering::SeqCst);
    } else {
        while BOOTED.load(Ordering::SeqCst) {
            spin_loop();
        }
        start_hart();
        println!("[kernel] -------- hart {} start --------", hartid!());
    }
    set_next_trigger();
    loop {
        executor::run();
    }
}

fn start_hart() {
    processor::init(hartid!());
    trap::init();
    kmm::refresh_tlb();
}

