#[naked]
#[no_mangle]
#[link_section = ".text.entry"]
unsafe extern "C" fn _entry() -> ! {
    asm!("
            mv      tp ,a0

            mv      gp ,a1
            // mv      t0, a0
            add     t0, a0, 1
            slli    t0, t0, {stack_size_bits}
            la      sp, {boot_stack}
            add     sp, sp, t0

            li      s0, {virt_addr_offset}
            or      sp, sp, s0

            la      t0, {page_table}
            srli    t0, t0, 12
            li      t1, 8 << 60
            or      t0, t0, t1
            csrw    satp, t0
            sfence.vma

            li      t1, {virt_addr_offset}
            or      gp, gp, t1

            mv      a1,gp
            la      t0, {entry}
            or      t0, t0, t1
            jalr    t0           
        ",
        page_table = sym PAGE_TABLE,
        boot_stack = sym BOOT_STACK,
        virt_addr_offset = const VIRT_ADDR_OFFSET,
        stack_size_bits = const STACK_SIZE_BITS,
        entry = sym first_init,
        options(noreturn),
    )
}

#[naked]
#[no_mangle]
pub(crate) unsafe extern "C" fn _second_start() {
    asm!("
            mv      tp ,a0
            mv      t0, a0
            slli    t0, t0, {stack_size_bits}
            la      sp, {boot_stack}
            add     sp, sp, t0

            li      s0, {virt_addr_offset}
            or      sp, sp, s0

            la      t0, {page_table}
            srli    t0, t0, 12
            li      t1, 8 << 60
            or      t0, t0, t1
            csrw    satp, t0
            sfence.vma

            la      t0, {entry}
            or      t0, t0, s0
            jalr    t0           
        ",
        boot_stack = sym BOOT_STACK,
        page_table = sym PAGE_TABLE,
        virt_addr_offset = const VIRT_ADDR_OFFSET,
        stack_size_bits = const STACK_SIZE_BITS,
        entry = sym second_init,
        options(noreturn),
    )
}

#[link_section = ".bss.stack"]
static mut BOOT_STACK: [u8; KSTACK_SIZ * NCPU] = [0; KSTACK_SIZ * NCPU];

#[link_section = ".data.prepage"]
static mut PAGE_TABLE: [PageTableEntry; 512] = {
    let mut arr: [PageTableEntry; 512] = [PageTableEntry { bits: 0 }; 512];
    arr[1] = PageTableEntry {
        bits: (0x40000 << 10) | 0xcf,
    };
    arr[2] = PageTableEntry {
        bits: (0x80000 << 10) | 0xcf,
    };
    arr[0x100] = PageTableEntry {
        bits: (0x00000 << 10) | 0xcf,
    };
    arr[0x101] = PageTableEntry {
        bits: (0x40000 << 10) | 0xcf,
    };
    arr[0x102] = PageTableEntry {
        bits: (0x80000 << 10) | 0xcf,
    };

    arr
};

#[no_mangle]
pub(crate) fn first_init(hart_id: usize, dtb: usize) {
    init_bss();
    early_init_logging();

    let platform_info = platform_info_from_dtb(dtb);
    println!("{:#?}", platform_info);
    kmm::init();
    platform::init(hart_id, dtb);
    enable_visit_user_memory();
    #[cfg(feature = "multicore")]
    init_other_hart(hart_id);

    rust_main(hart_id, dtb);
}

#[no_mangle]
pub(crate) extern "C" fn second_init(hart_id: usize, dtb: usize) {
    enable_visit_user_memory();
    rust_main(hart_id, dtb);
}

// 唤醒其它核
//
// 对于qemu来说，只需要工具所有的核都是一样的，因此从0号核开始唤醒。
// 对于visionfive2来说，0号核只有M态，因此不进行唤醒
#[allow(unused)]
pub fn init_other_hart(hart_id: usize) {
    let aux_core_func = (_second_start as usize) & (!VIRT_ADDR_OFFSET);
    let start_hart = if cfg!(any(feature = "vf2", feature = "hifive")) {
        1
    } else {
        0
    };
    for i in start_hart..NCPU {
        if i != hart_id {
            println!("[init_other_hart] secondary addr: {:#x}", aux_core_func);

            let res = hart_start(i, aux_core_func, 0);
            if res.error == 0 {
                println!("[init_other_hart] hart {:x} start successfully", i);
                break;
            }
        }
    }
}

use core::panic::PanicInfo;

use klog::sbi::shutdown;

#[panic_handler]
fn _panic(info: &PanicInfo) -> ! {
    if let Some(location) = info.location() {
        println!(
            "[kernel] hart {} panicked at {}:{} {}",
            hartid!(),
            location.file(),
            location.line(),
            info.message().unwrap()
        );
    } else {
        println!("[kernel] hart {} panicked: {}", 0, info.message().unwrap());
    }
    shutdown()
}

