pub async fn add_initproc() {
    #[cfg(feature = "busybox")]
    let data = get_busybox_data().await.unwrap();
    #[cfg(feature = "runtests")]
    let data = get_test_data().await.unwrap();
    #[cfg(feature = "customized-sh")]
    let data = get_shell_data().await.unwrap();
    #[cfg(feature = "preliminary")]
    let data = get_preliminary_data().await.unwrap();
    #[cfg(feature = "uitest")]
    let data = get_uitest_data().await.unwrap();
    Task::new(data).await;
}

