#[derive(Copy, Clone, PartialEq, Eq, Debug)]
pub enum TaskStatus {
    Ready,   // 准备运行
    Running, // 正在运行
    Zombie,  // 僵尸态
}

pub struct Task {
    pub task_id: TaskId,
    pub task_status: SpinMutex<TaskStatus>,

    pub tgid: AtomicUsize,
    pub pgid: AtomicUsize,

    pub memory_set: Arc<SpinMutex<MemorySet>>,
    pub fd_table: Arc<SpinMutex<FdTable>>,
    pub thread_group: Arc<SpinMutex<ThreadGroup>>,
    pub futex_queue: Arc<SpinMutex<FutexQueue>>,
    pub pcb: Arc<SpinMutex<ProcessInfo>>,

    pub threadinfo: SyncUnsafeCell<ThreadInfo>,
    pub exit_signal: AtomicU8,
    // signal
    pub pending_signals: Arc<SpinMutex<PendingSigs>>,
    pub sigactions: Arc<SpinMutex<SigActions>>,
    pub sig_struct: SyncUnsafeCell<SignalStruct>,

    // irq
    pub interrupt_count: SpinMutex<BTreeMap<usize, usize>>,
    // exit
    pub exitcode: AtomicI32,
}

pub struct ProcessInfo {
    pub trap_cause: Option<Scause>,

    pub parent: Option<Weak<Task>>,

    pub children: Vec<Arc<Task>>,

    pub current_path: AbsolutePath,

    pub interval_timer: Option<IntervalTimer>,

    // futex
    // pub futex_queue: FutexQueue,
    pub robust_list: RobustList,

    // process resource
    pub rlimit_nofile: RLimit,
    // #[cfg(not(feature = "multicore"))]
    // pub pselect_times: u8,
}

pub struct ThreadInfo {
    pub trap_context: TrapContext,

    pub waker: Option<Waker>,

    pub cpu_mask: CpuMask,

    pub timeinfo: TimeInfo,

    pub clear_child_tid: Option<usize>,

    pub set_child_tid: Option<usize>,
}

pub struct SignalStruct {
    pub sigmask: SigMask, // 用于表明被阻塞的信号，任务不处理这些信号

    // pub sigactions: SigActions,
    pub sigucontext_ptr: AtomicUsize,

    pub sigstack: Option<SignalStack>,
}

impl SignalStruct {
    pub fn new() -> Self {
        Self {
            sigmask: SigMask::empty(),
            // sigactions: SigActions::new(),
            sigucontext_ptr: AtomicUsize::new(0),
            sigstack: None,
        }
    }
}

impl Task {
    pub fn token(&self) -> usize {
        self.memory_set.lock().token()
    }

    pub fn get_taskid(&self) -> usize {
        self.task_id.0
    }

    // pub fn get_tgid(self: &Arc<Self>) -> usize {
    //     self.get_leader().get_taskid()
    // }

    pub fn get_pgid(&self) -> usize {
        self.pgid.load(Ordering::SeqCst)
    }

    pub fn set_pgid(&self, pid: usize) {
        self.pgid.store(pid, Ordering::SeqCst);
    }

    pub fn tgid(&self) -> usize {
        self.tgid.load(Ordering::SeqCst)
    }

    // pub fn clear_child_tid(&self) -> Option<usize> {
    //     unsafe { (*self.threadinfo.get()).clear_child_tid }
    // }

    // pub fn set_tgid(&self, pid: TaskId) {
    //     self.tgid.store(pid.0, Ordering::SeqCst);
    // }

    // pub fn get_leader(self: &Arc<Self>) -> Arc<Task> {
    //     let task = &self.pcb().thread_group.group_leader;
    //     if task.is_none() {
    //         self.clone()
    //     } else {
    //         task.as_ref().unwrap().upgrade().unwrap()
    //     }
    // }

    pub fn is_group_leader(&self) -> bool {
        // self.lock().thread_group.is_group_leader()
        self.get_taskid() == self.tgid()
    }

    pub fn is_zombie(&self) -> bool {
        *self.task_status.lock() == TaskStatus::Zombie
    }

    pub fn set_zombie(&self) {
        *self.task_status.lock() = TaskStatus::Zombie;
    }

    pub fn set_exitcode(&self, exitcode: i32) {
        self.exitcode.store(exitcode, Ordering::SeqCst);
    }

    pub fn exitcode(&self) -> i32 {
        self.exitcode.load(Ordering::SeqCst)
    }

    pub fn set_exitsignal(&self, exitsignal: u8) {
        self.exit_signal.store(exitsignal, Ordering::SeqCst);
    }

    pub fn exitsignal(&self) -> u8 {
        self.exit_signal.load(Ordering::SeqCst)
    }

    pub fn pcb_map<T>(&self, f: impl FnOnce(&mut ProcessInfo) -> T) -> T {
        f(&mut self.pcb.lock())
    }

    pub fn thread_group_map<T>(&self, f: impl FnOnce(&mut ThreadGroup) -> T) -> T {
        f(&mut self.thread_group.lock())
    }

    pub fn futex_map<T>(&self, f: impl FnOnce(&mut FutexQueue) -> T) -> T {
        f(&mut self.futex_queue.lock())
    }

    /// Terminate this task
    pub fn terminate(&self) {
        self.set_zombie();
    }

    pub fn trap_context(&self) -> &TrapContext {
        unsafe { &(*self.threadinfo.get()).trap_context }
    }

    pub fn trap_context_mut(&self) -> &mut TrapContext {
        unsafe { &mut (*self.threadinfo.get()).trap_context }
    }

    // pub fn sig_context(&self) -> &Option<UContext> {
    //     unsafe { &(*self.sig_struct.get()).sigcontext }
    // }

    // pub fn sig_context_mut(&self) -> &mut Option<UContext> {
    //     unsafe { &mut (*self.sig_struct.get()).sigcontext }
