pub async fn user_loop(task: Arc<Task>) {
    task.waker(async_utils::take_waker().await);
    loop {
        if task.is_zombie() {
            // trace!("task {} is zombie", task.get_taskid());
            break;
        }
        trap_return(&task);
        if task.is_zombie() {
            // trace!("task {} is zombie", task.get_taskid());
            break;
        }
        user_trap_handler(&task).await;
        if task.is_zombie() {
            // trace!("task {} is zombie", task.get_taskid());
            break;
        }
        // handle_timeout_events();
        check_interval_timer(&task);
        let _ = check_signal(&task);
    }
    info!("task {} terminated", task.get_taskid());
    handle_exit(&task);
}

pub struct UserTaskFuture<F: Future + Send + 'static> {
    task: Arc<Task>,
    task_future: F,
    // env: EnvContext,
}

impl<F: Future + Send + 'static> UserTaskFuture<F> {
    pub fn new(task: Arc<Task>, future: F) -> Self {
        Self {
