/// Things the task need to do when it terminated
pub fn handle_exit(task: &Arc<Task>) {
    assert_ne!(
        task.get_taskid(),
        INIT_PROCESS,
        "initproc die!!!, sepc {:#x}",
        task.trap_context_mut().sepc
    );
    info!("[handle_exit]: process/thread do exit");
    let tid = task.get_taskid();
    if tid == INIT_PROCESS {
        shutdown();
    }
    let mut pcb = task.pcb();
    // if !pcb.children.is_empty() {
    //     for child in pcb.children.iter() {
    //         let initproc = TASK_MANAGER.init_proc();
    //         // child.terminate();
    //         child.pcb().parent = Some(Arc::downgrade(&initproc));
    //         initproc.pcb().children.push(child.clone());
    //     }
    // }

    if let Some(tidaddress) = task.clear_child_tid() {
        info!("[handle exit] clear child tid {:#x}", tidaddress);
        check_mut_slice(tidaddress as *mut u8, core::mem::size_of::<usize>());
        unsafe {
            *(tidaddress as *mut u8) = 0;
        }
        // task.pcb_map(|proc| proc.futex_queue.wake(tidaddress as u32, 1));
        task.futex_queue.lock().wake(tidaddress as u32, 1);
    }

    // let exit_signal = task.exitsignal();
    if !task.is_group_leader() {
        pcb.children.clear();
        task.thread_group.lock().remove(tid);
        info!(
            "handle exit thread_group len {:?}",
            task.thread_group.lock().total_num()
        );
        TASK_MANAGER.remove(tid);
    } else {
        if !pcb.children.is_empty() {
            for child in pcb.children.iter() {
                let initproc = TASK_MANAGER.init_proc();
                // child.terminate();
                child.pcb().parent = Some(Arc::downgrade(&initproc));
                initproc.pcb().children.push(child.clone());
            }
            pcb.children.clear();
        }
        if let Some(proc) = pcb.parent.clone() {
            let parent = proc.upgrade().unwrap();
            let signo: i32 = Signal::SIGCHLD.into();
            let siginfo = SigInfo {
                si_signo: signo,
                si_code: SigCode::User,
                si_errno: 0,
                otherinfo: OtherInfo::Extend {
                    si_pid: task.tgid() as u32,
                    si_status: Some(task.exitcode()),
                    si_utime: None,
                    si_stime: None,
                },
            };
            parent.proc_recv_siginfo(siginfo);
        } else {
            pcb.children.clear();
        }
        task.fd_table.lock().table.clear();
    }
}

