/// ## 判断虚拟地址是否超出了用户空间
///
/// 如果虚拟地址超出了用户空间，返回Err(SystemError::EFAULT).
/// 如果end < start，返回Err(SystemError::EOVERFLOW)
///
/// 否则返回Ok(())
pub fn verify_area(addr: VirtAddr, size: usize) -> Result {
    let end = addr.add(size);
    if unlikely(end.0 < addr.0) {
        // return Err(SystemError::EOVERFLOW);
        return Err(Errno::EOVERFLOW);
    }
    if !addr.is_user() || !end.is_user() {
        return Err(Errno::EFAULT);
    }
    Ok(0)
}

pub fn check_mut_slice(buf: *mut u8, len: usize) {
    let buf_start: VirtAddr = VirtAddr::from(buf as usize).floor().into();
    let buf_end: VirtAddr = VirtAddr::from(buf as usize + len).ceil().into();
    let mut va = buf_start;
    while va < buf_end {
        // trace!(
