/// Mmap Block Manager
///
/// - mmap_start: Starting virtual address of mmap blocks in the address space.
/// - mmap_top: Highest used virtual address of mmap blocks in the address
///   space.
/// - mmap_map: Virtual page number to mmap page mapping.
/// - frame_trackers: Virtual page number to physical page frame mapping.
#[derive(Clone)]
pub struct MmapManager {
    pub mmap_start: VirtAddr,
    pub mmap_top: VirtAddr,
    pub mmap_map: BTreeMap<VirtPageNum, MmapPage>,
    pub frame_trackers: BTreeMap<VirtPageNum, FrameTracker>,
}
impl MmapManager {
    pub fn new(mmap_start: VirtAddr, mmap_top: VirtAddr) -> Self {
        Self {
            mmap_start,
            mmap_top,
            mmap_map: BTreeMap::new(),
            frame_trackers: BTreeMap::new(),
        }
    }
    pub fn get_mmap_top(&mut self) -> VirtAddr {
        self.mmap_top
    }
    pub fn push(
        &mut self,
        start_va: VirtAddr,
        len: usize,
        prot: MmapProts,
        flags: MmapFlags,
        offset: usize,
        file: Option<Arc<dyn File>>,
    ) -> usize {
        let end = VirtAddr(start_va.0 + len);
        // use lazy map
        let mut offset = offset;
        for vpn in VPNRange::from_va(start_va, end) {
            debug!("[DEBUG] mmap map vpn:{:x?}", vpn);
            let mmap_page = MmapPage::new(vpn, prot, flags, false, file.clone(), offset);
            self.mmap_map.insert(vpn, mmap_page);
            offset += PAGE_SIZE;
        }
        // update mmap_top
        if self.mmap_top <= start_va {
            self.mmap_top = (start_va.0 + len).into();
        }
        start_va.0
    }
    pub fn remove(&mut self, start_va: VirtAddr, len: usize) {
        let end_va = VirtAddr(start_va.0 + len);
        for vpn in VPNRange::from_va(start_va, end_va) {
            self.mmap_map.remove(&vpn);
            self.frame_trackers.remove(&vpn);
        }
    }
}

/// Mmap Block
///
/// Used to record information about mmap space. Mmap data is not stored here.
#[derive(Clone)]
pub struct MmapPage {
    /// Starting virtual address of mmap space
    pub vpn: VirtPageNum,
    /// Mmap space validity
    pub valid: bool,
    /// Mmap space permissions
    pub prot: MmapProts,
    /// Mapping flags
    pub flags: MmapFlags,
    /// File descriptor
    pub file: Option<Arc<dyn File>>,
    /// Mapped file offset address
    pub offset: usize,
}

impl MmapPage {
    pub fn new(
        vpn: VirtPageNum,
        prot: MmapProts,
        flags: MmapFlags,
        valid: bool,
        file: Option<Arc<dyn File>>,
        offset: usize,
    ) -> Self {
        Self {
            vpn,
            prot,
            flags,
            valid,
            file,
            offset,
        }
    }
    pub async fn lazy_map_page(&mut self, token: usize) {
        if self.flags.contains(MmapFlags::MAP_ANONYMOUS) {
            self.read_from_zero(token);
        } else {
            self.read_from_file(token).await;
        }
        self.valid = true;
    }
    #[allow(unused_must_use)]
    async fn read_from_file(&mut self, token: usize) {
        #[cfg(feature = "time_tracer")]
        time_trace!("mmap_read_from_file");
        let f = self.file.clone().unwrap();
        let old_offset = f.offset();
        let _ = f.lseek(SeekFrom::SeekSet(self.offset.try_into().unwrap()));
        if !f.readable() {
            return;
        }
        let file_size = f.file_size();
        let len = PAGE_SIZE.min(file_size - self.offset);
        let buf = translated_bytes_buffer(token, VirtAddr::from(self.vpn).0 as *const u8, len);
        for b in buf.into_iter() {
            f.read(b.len(), b).await;
        }
        f.lseek(SeekFrom::SeekSet(old_offset.try_into().unwrap()));
        return;
    }
    fn read_from_zero(&mut self, token: usize) {
        UserBuffer::wrap(translated_bytes_buffer(
            token,
            VirtAddr::from(self.vpn).0 as *const u8,
            PAGE_SIZE,
        ))
        .write_zeros();
    }
    #[allow(unused)]
    pub fn write_back(&mut self, token: usize) {
        let f = self.file.clone().unwrap();
        let old_offset = f.offset();
        f.lseek(SeekFrom::SeekSet(self.offset.try_into().unwrap()));
        if !f.writable() {
            return;
        }
        let buf =
            translated_bytes_buffer(token, VirtAddr::from(self.vpn).0 as *const u8, PAGE_SIZE);
        for b in buf.into_iter() {
            f.write(b.len(), b);
        }
        f.lseek(SeekFrom::SeekSet(old_offset.try_into().unwrap()));
        return;
    }
    pub fn set_prot(&mut self, new_prot: MmapProts) {
        self.prot = new_prot;
    }
}

