impl Drop for Pipe {
    fn drop(&mut self) {
        info!("[Pipe::drop] start drop..., writable {}", self.writable);
        if self.writable {
            // Write end,
            // we should wake up all read waiters(if any)
            let mut buffer = self.buffer.lock();
            while !buffer.read_waiters.is_empty() {
                let waker = buffer.read_waiters.pop().unwrap();
                info!("[Pipe::drop] wake up");
                waker.wake();
            }
        } else if self.readable {
            let mut buffer = self.buffer.lock();
            while !buffer.write_waiters.is_empty() {
                let waker = buffer.write_waiters.pop().unwrap();
                info!("[Pipe::drop] wake up");
                waker.wake();
            }
        }
    }
}

#[derive(Copy, Clone, PartialEq)]
enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

const RING_BUFFER_SIZE: usize = 4096;

pub struct PipeRingBuffer {
    /// Buffer memory block
    arr: [u8; RING_BUFFER_SIZE],
    /// Queue head, read
    head: usize,
    /// Queue tail, write
    tail: usize,
    /// Queue status
    status: RingBufferStatus,
    /// Save a weak reference count of its write end.
    /// Used to determine if all write ends of the pipe have been closed.
    write_end: Option<Weak<Pipe>>,
    /// Save a weak reference count of its read end.
    /// Used to determine if all read ends of the pipe have been closed.
    read_end: Option<Weak<Pipe>>,
    /// Waker
    write_waiters: Vec<Waker>,
    read_waiters: Vec<Waker>,
}

impl PipeRingBuffer {
    pub fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
            write_end: None,
            read_end: None,
            write_waiters: Vec::new(),
            read_waiters: Vec::new(),
        }
    }
    pub fn set_write_end(&mut self, write_end: &Arc<Pipe>) {
        self.write_end = Some(Arc::downgrade(write_end));
    }

    fn set_read_end(&mut self, read_end: &Arc<Pipe>) {
        self.read_end = Some(Arc::downgrade(read_end));
    }
    /// Write a byte to the tail of the pipe
    pub fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }
    /// Read a byte from the head of the pipe
    pub fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }
    /// Get the remaining readable length in the pipe
    pub fn available_read(&self) -> usize {
        if self.status == RingBufferStatus::Empty {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }
    /// Get the remaining writable length in the pipe
    pub fn available_write(&self) -> usize {
        if self.status == RingBufferStatus::Full {
            0
        } else {
            RING_BUFFER_SIZE - self.available_read()
        }
    }

    fn read_range(&mut self, buf: &mut [u8]) -> usize {
        self.status = RingBufferStatus::Normal;
        let end = match self.tail > self.head {
            true => self.tail,
            false => RING_BUFFER_SIZE,
        };
        let ret = (end - self.head).min(buf.len());
        let end = self.head + ret;
        buf[..ret].copy_from_slice(&mut self.arr[self.head..end]);
        self.head = end % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        ret
    }

    fn write_range(&mut self, buf: &[u8]) -> usize {
        self.status = RingBufferStatus::Normal;
        let end = match self.head > self.tail {
            true => self.head,
            false => RING_BUFFER_SIZE,
        };
        let ret = (end - self.tail).min(buf.len());
        let end = self.tail + ret;
        self.arr[self.tail..end].copy_from_slice(&buf[..ret]);
        self.tail = end % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
        ret
    }

    /// Check if all write ends of the pipe have been closed by the weak pointer
    /// of the pipe buffer write end
    pub fn all_write_ends_closed(&self) -> bool {
        trace!(
            "[all_write_end_closed] write end ref cnt {}",
            self.write_end.as_ref().unwrap().strong_count()
        );
        self.write_end.as_ref().unwrap().upgrade().is_none()
    }

    /// Check if all read ends of the pipe have been closed by the weak pointer
    /// of the pipe buffer read end
    fn all_read_ends_closed(&self) -> bool {
        trace!(
            "read end ref cnt {}",
            self.read_end.as_ref().unwrap().strong_count()
        );
        self.read_end.as_ref().unwrap().upgrade().is_none()
    }

    fn wait_for_reading(&mut self, waker: Waker) {
        self.read_waiters.push(waker);
    }

    fn wait_for_writing(&mut self, waker: Waker) {
        self.write_waiters.push(waker);
    }

    fn wake(&mut self, for_reader: bool) {
        let queue = match for_reader {
            true => &mut self.read_waiters,
            false => &mut self.write_waiters,
        };
        while !queue.is_empty() {
            let waker = queue.pop().unwrap();
            debug!("[Pipe::wake] wake up");
            waker.wake();
        }
    }
}

/// Create a pipe and return the read end and write end of the pipe (read_end,
/// write_end)
pub fn make_pipe() -> (Arc<Pipe>, Arc<Pipe>) {
    let buffer = Arc::new(Mutex::new(PipeRingBuffer::new()));
    let read_end = Arc::new(Pipe::read_end_with_buffer(buffer.clone()));
    let write_end = Arc::new(Pipe::write_end_with_buffer(buffer.clone()));

    buffer.lock().set_write_end(&write_end);
    buffer.lock().set_read_end(&read_end);

    (read_end, write_end)
}

