impl NetInterfaceInner {
    fn new() -> Self {
        // stack_trace!();
        let mut device = Loopback::new(Medium::Ethernet);
        let iface = {
            let mut config = match device.capabilities().medium {
                Medium::Ethernet => {
                    Config::new(EthernetAddress([0x02, 0x00, 0x00, 0x00, 0x00, 0x01]).into())
                }
                Medium::Ip => Config::new(smoltcp::wire::HardwareAddress::Ip),
            };
            config.random_seed = 0x9898998;
            let mut iface = Interface::new(
                config,
                &mut device,
                Instant::from_millis(get_time_duration().as_millis() as i64),
            );
            iface.update_ip_addrs(|ip_addrs| {
                ip_addrs
                    .push(IpCidr::new(IpAddress::v4(127, 0, 0, 1), 24))
                    .unwrap();
                ip_addrs
                    .push(IpCidr::new(IpAddress::v6(0, 0, 0, 0, 0, 0, 0, 1), 128))
                    .unwrap();
            });
            let gate_way = IpAddress::v4(127, 0, 0, 1);
            match gate_way {
                IpAddress::Ipv4(v4) => iface.routes_mut().add_default_ipv4_route(v4).unwrap(),
                IpAddress::Ipv6(_) => todo!(),
            };
            iface
        };
