    }
}

impl KernelNetInterface {
    pub fn init(&self) {
        // stack_trace!();
        *self.inner.lock() = Some(NetInterfaceInner::new());
    }

    pub fn poll(&self) -> bool {
        // stack_trace!();
        info!("[NetInterface::poll] poll...");
        let mut binding = self.inner.lock();
        // info!("11111");
        let inner = binding.as_mut().unwrap();
        let iface = &mut inner.iface;
        let device = &mut inner.device;
        let mut sockets = SOCKET_SET.lock();
        // info!("get sockets and enter iface poll");
        let a = iface.poll(
            Instant::from_millis(get_time_duration().as_millis() as i64),
            device,
            &mut sockets,
        );
        if !a {
            info!("[NetInterface::poll] poll failed");
        } else {
            info!("[NetInterface::poll] poll successfully");
        }
        info!("finish poll");
        a
    }
    pub fn inner_handler<T>(&self, f: impl FnOnce(&mut NetInterfaceInner) -> T) -> T {
        f(&mut self.inner.lock().as_mut().unwrap())
    }
}

