    /// #define SYS_pipe2 59
    pub fn sys_pipe2(&self, pipe: *mut i32, _flag: usize) -> Result {
        let mut fd_table = self.task.fd_table.lock();
        let (pipe_read, pipe_write) = make_pipe();

        let read_fd = fd_table.alloc_fd().unwrap();
        let fd_limit = fd_table.rlimit.rlim_cur;
        if read_fd as usize >= fd_limit {
            return_errno!(Errno::EMFILE);
        }
        fd_table.table[read_fd as usize] = Some(pipe_read);

        let write_fd = fd_table.alloc_fd().unwrap() as usize;
        if write_fd >= fd_limit {
            return_errno!(Errno::EMFILE);
        }
        fd_table.table[write_fd] = Some(pipe_write);

        let buf = unsafe { core::slice::from_raw_parts_mut(pipe, 2 * core::mem::size_of::<i32>()) };
        buf[0] = read_fd as i32;
        buf[1] = write_fd as i32;
        info!("[sys_pipe]: read fd {}, write fd {}", read_fd, write_fd);
        Ok(0)
    }

    /// #define SYS_dup 23
    ///
    /// 功能：复制文件描述符；
    ///
    /// 输入：
    ///
    /// - fd：被复制的文件描述符。
    ///
    /// 返回值：
    ///
    /// - 成功：返回新的文件描述符。
    /// - 失败：返回-1。
    ///
    /// ```c
    /// int fd;
    /// int ret = syscall(SYS_dup, fd);
    /// ```
    pub fn sys_dup(&self, fd: usize) -> Result {
        debug!("[sys_dup2] start...");
        let mut fd_table = self.task.fd_table.lock();
        // 检查传入 fd 的合法性
        if fd >= fd_table.table.len() {
            return_errno!(Errno::EBADF, "oldfd is out of range, oldfd: {}", fd);
        }
        if fd_table.table[fd].is_none() {
            return_errno!(Errno::EBADF, "oldfd is not exist, oldfd {}", fd);
        }
        let new_fd = fd_table.alloc_fd().unwrap() as usize;
        let fd_limit = fd_table.rlimit.rlim_cur;
        if new_fd >= fd_limit {
            return_errno!(Errno::EMFILE, "too many fd, newfd: {}", new_fd);
        }
        fd_table.table[new_fd] = Some(Arc::clone(fd_table.table[fd].as_ref().unwrap()));

        Ok(new_fd as isize)
    }

    // #define SYS_dup3 24
    pub fn sys_dup3(&self, old_fd: usize, new_fd: usize) -> Result {
        debug!("[sys_dup3] start... oldfd:{}, newfd:{}", old_fd, new_fd);
        let task = self.task;
        let fd_table = &mut task.fd_table.lock().table;

        if old_fd >= fd_table.len() || fd_table[old_fd].is_none() {
            return_errno!(Errno::EBADF);
        }
        if new_fd >= fd_table.len() {
            for _ in fd_table.len()..(new_fd + 1) {
                fd_table.push(None);
            }
        }

        fd_table[new_fd] = Some(fd_table[old_fd].as_ref().unwrap().clone());
        Ok(new_fd as isize)
    }

