/// kernel back to user
pub fn trap_return(task: &Arc<Task>) {
    // interrupt_disable();
    set_user_trap_entry();
    // let _ = check_signal(&task);

    let cx = task.trap_context_mut();
    debug!("trap return sepc {:#x}", cx.sepc);
    debug!("trap return, sp {:#x}", cx.x[2]);
    debug!("trap return, fp {:#x}", cx.kernel_fp);
    task.timeinfo_mut().record_kernel_to_user();
    take_current_trap_cx().freg.restore();
    unsafe { sstatus::set_fs(sstatus::FS::Clean) };
    unsafe {
        user_trapret(take_current_trap_cx());
    }
    take_current_trap_cx()
        .freg
        .mark_save_if_needed(take_current_trap_cx().sstatus);

    task.timeinfo_mut().record_user_to_kernel();
}

