/// 内核态 trap 发生时的处理函数
#[no_mangle]
pub fn kernel_trap_handler() {
    // 定义一个内核中断处理函数
    let scause = scause::read();
    // 读取当前中断原因
    let stval = stval::read();
    // 读取附加的异常信息
    // showsstatus();
    // println!("kernel_trap_handler: scause: {:?}", scause.cause());
    // 匹配当前中断原因
    match scause.cause() {
        // 处理外部中断
        // Trap::Interrupt(Interrupt::SupervisorExternal) => {
        //     // error!("external interrrupt!!");
        //     // todo:处理外部中断
        //     // crate::driver::intr_handler();
        // }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            let task = take_current_task();
            trace!(
                "kernel_trap_handler: memory fault, task: at {:#x}, {:#x}, scause {:?} stval {:#x} taskid {:?}",
                VirtAddr::from(stval as usize).0,
                VirtAddr::from(stval as usize).floor().0,
                scause.cause(),
                stval as usize,
                task.get_taskid(),
            );
            let va: VirtAddr = (stval as usize).into();
            // let task = take_current_task();

            let lazy: isize = task.check_lazy_async(va);
            if lazy != 0 {
                trace!("task {:?} terminate",task.get_taskid());
                task.terminate();
            }
        }
        // 处理定时器中断
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            info!("kernel timer interrrupt!!");
            TIMER_QUEUE.handle_timeout(get_time_duration());
            set_next_trigger();
            // 设置下一个触发器
            // yield_now().await;
        }
        // 处理其他异常
        _ => {
            // error!("other exception!!");
            // 记录其他异常
            error!(
                // 打印错误信息
                "[kernel] {:?}(scause:{}) in application, bad addr = {:#x}, bad instruction =
{:#x}, kernel panicked!!",                 scause::read().cause(),
                scause::read().bits(),
                stval::read(),
                sepc::read(),
            );
            panic!(
                "a trap {:?} from kernel! stval {:#x}",
                scause::read().cause(),
                stval::read()
            );
        }
    }
}

/// 用户态 trap 发生时的处理函数
#[no_mangle]
pub async fn user_trap_handler(task:&Arc<Task>) {
    set_kernel_trap_entry();
    let mut cx = task.trap_context_mut();
    let scause = scause::read();
    let stval = stval::read();
    // showsstatus();
    // info!(
    //     "trap in, sepc {:#x}, user sp {:#x}, kernel sp {:#x}",
    //     cx.sepc, cx.x[2], cx.kernel_sp,
    // );
    // interrupt_enable();
    if scause.is_exception() {
        task.interrupt_count(scause.code());
    }
    if task.timeinfo().schedule() && executor::has_task() {
        log::info!("time slice used up, yield now");
        yield_now().await;
    }
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            cx.sepc += 4;
            trace!("syscall_id:{:?}", cx.a7());
            // info!("syscall_id:{:?}", cx.a7());
            // debug!("syscall_a0:{:x}", cx.a0());
            // debug!("syscall_a1:{:x}", cx.a1());
            // debug!("syscall_a2:{:x}", cx.a2());
            let result = Syscall::new(task)
            .syscall(
                cx.a7(),
                [cx.a0(), cx.a1(), cx.a2(), cx.a3(), cx.a4(), cx.a5()],
            )
            .await;
            trace!("syscall result {:#x}", result);
            cx = task.trap_context_mut();
            cx.set_a0(result as usize);
        }

        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            let task = take_current_task();
            info!(
                "user_trap_handler: memory fault, task: at {:#x}, {:#x}, scause {:?} stval {:#x} taskid {:?}",
                VirtAddr::from(stval as usize).0,
                VirtAddr::from(stval as usize).floor().0,
                scause.cause(),
                stval as usize,
                task.get_taskid(),
            );
            let va: VirtAddr = (stval as usize).into();


            let lazy: isize = task.check_lazy_async(va);
            if lazy != 0 {
                trace!("task {:?} terminate",task.get_taskid());
                task.terminate();
            }
        }

        Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault) => {
            info!("Trap InstructionPageFault");
            // let task = take_current_task();
            info!(
                "{:?} in task {}, bad addr = {:#x}, bad instruction = {:#x}.",
                scause.cause(),
                task.get_taskid(),
                stval,
                task.trap_context().sepc,
            );
            // current_add_signal(Signal::SIGSEGV);
            trace!("task {:?} terminate",task.get_taskid());
            task.terminate();
            // panic!()
        }

        Trap::Exception(Exception::IllegalInstruction) => {
            warn!(
                "[kernel] IllegalInstruction in application, kernel killed it, stval {:#x}, sepc {:#x}",
                stval,
                sepc::read(),
            );
            // let task = take_current_task();
            trace!("task {:?} terminate",task.get_taskid());
            task.terminate();
            panic!();
            // terminate_all_tasks();
        }

        // 时间片到了
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            debug!(
                "[trap_handler] timer interrupt, sepc {:#x}",
                task.trap_context().sepc
            );
            TIMER_QUEUE.handle_timeout(get_time_duration());
            // handle_timeout_events();
            set_next_trigger();
            yield_now().await
        }

        _ => panic!(
            "trap {:?} is unsupported, stval = {:#x}!",
            scause.cause(),
            stval
        ),
    }
}

pub fn check_interval_timer(task:&Arc<Task>) {
    // let task = take_current_task();
    let mut inner = task.pcb();
    if inner.interval_timer.is_none() {
        return;
    }

    let itimer = inner.interval_timer.as_mut().unwrap();
    let duration = get_timeval() - itimer.creation_time;
    let itime_value = itimer.timer_value;
    // INFO: 现在只处理 ITIMER_REAL
    if duration > itime_value.it_value {
        if itime_value.it_interval == TimeVal::zero() {
            inner.interval_timer = None;
        } else {
            itimer.timer_value.it_value = itimer.timer_value.it_interval;
        }
        task.proc_recv_siginfo(SigInfo {
            si_signo: Signal::SIGALRM.into(),
            si_code: SigCode::Kernel,
            si_errno: 0,
            otherinfo: OtherInfo::Basic,
        })
    }
}

