pub struct PendingSigs {
    pub signal: SigMask,
    pub sigs_queue: VecDeque<SigInfo>,
    pub waker: Option<Waker>,
    pub should_wake: SigMask,
}

impl PendingSigs {
    pub fn new() -> Self {
        Self {
            sigs_queue: VecDeque::new(),
            signal: SigMask::empty(),
            waker: None,
            should_wake: SigMask::empty(),
        }
    }
    pub fn pop(&mut self) -> Option<SigInfo> {
        if let Some(siginfo) = self.sigs_queue.pop_front() {
            self.signal.sub(siginfo.si_signo as u32);
            Some(siginfo)
        } else {
            None
        }
    }
    pub fn push(&mut self, siginfo: SigInfo) {
        self.sigs_queue.push_back(siginfo);
    }

    #[inline]
    pub fn set_waker(&mut self, waker: Option<Waker>) {
        self.waker = waker;
    }

    pub fn push_with_check(&mut self, siginfo: SigInfo) {
        if self.signal.if_contains(siginfo.si_signo as u32) {
            return;
        } else {
            self.signal.add(siginfo.si_signo as u32);
            self.push(siginfo);
        }
        if let Some(waker) = self.waker.as_ref() {
            waker.wake_by_ref();
        }
    }

    #[inline]
    pub fn has_expect_signals(&self, expect: SigMask) -> bool {
        !(expect & self.signal).is_empty()
    }

    #[inline]
    pub fn has_expect_signal(&self, expect: Vec<Signal>) -> Option<SigInfo> {
        for signal in expect {
            if self.signal.if_contains(signal as u32) {
                return Some(
                    self.sigs_queue
                        .iter()
                        .find(|si| si.si_signo == signal as i32)
                        .unwrap()
                        .clone(),
                );
            }
        }
        return None;
    }

    pub fn is_empty(&self) -> bool {
        self.sigs_queue.is_empty()
    }

    pub fn total_len(&self) -> usize {
        self.sigs_queue.len()
    }

    pub fn dequeue_except(&mut self, except: SigMask) -> Option<SigInfo> {
        let x = self.signal & except;
        if x.is_empty() {
            return None;
        }
        for i in 0..self.sigs_queue.len() {
            let sig = self.sigs_queue[i].si_signo;
            if x.if_contains(sig as u32) {
                self.signal.sub(sig as u32);
                return self.sigs_queue.remove(i);
            }
        }
        error!("[dequeue_except] I suppose it won't go here");
        None
    }
}
