}

impl SigActions {
    pub fn new() -> Self {
        let sigactions: [KSigAction; SIG_NUM] =
            core::array::from_fn(|signo| KSigAction::new(Signal::from(signo + 1)));
        Self { sigactions }
    }

    pub fn get(&self, signo: usize) -> Option<&KSigAction> {
        if signo < SIG_NUM {
            Some(&self.sigactions[signo])
        } else {
            None
        }
    }

    pub fn set_sigaction(&mut self, signo: usize, sigaction: KSigAction) {
        if signo < SIG_NUM {
            self.sigactions[signo] = sigaction;
        }
    }

    /// it is used in execve because it changed the memory
    pub fn reset_self(&mut self) {
        for n in 0..SIG_NUM {
            match self.sigactions[n].sa_type {
                SaHandlerType::Customized { .. } => {
                    self.sigactions[n].sa_type =
                        SaHandlerType::default(Signal::from((n + 1) as usize));
                }
                _ => {}
            }
        }
    }
}

