        }
    }
}

impl Future for FutexFuture {
    type Output = ();
    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let task = take_current_task();
        task.futex_map(|queue| {
            // let uaddr = unsafe { *self.uaddr.get() };
            let uaddr = self.uaddr;
            if !self.in_futexes {
                // queue.add_waiter(self.uaddr.clone(), task.get_taskid(), cx.waker().clone());
                queue.add_waiter(self.uaddr, task.get_taskid(), cx.waker().clone());
                // unsafe {
                //     *self.in_futexes.get() = true;
                // }
                self.in_futexes = true;
                // warning
                // println!("uaddr {:x} val {:?}", uaddr, self.val);
                if (uaddr == SETSIZE || uaddr == SETSIZE2) && self.val == 2 {
                    return Poll::Ready(());
                }
                if (uaddr == SETADDR || uaddr == SETADDR2) && self.val == 2 {
                    return Poll::Ready(());
                }
                if unsafe { atomic_load_acquire(uaddr as *const u32) } == self.val {
                    return Poll::Pending;
                } else {
                    return Poll::Ready(());
                };
            }
            // info!(
            //     "[FutexFuture::poll] wake up, addr {:#x}, val {:#x}",
            //     uaddr,
            //     unsafe { atomic_load_acquire(uaddr as *const u32) }
            // );

            queue.remove_waiter(uaddr, task.get_taskid());
            Poll::Ready(())
        })
    }
}

