// 这段代码展示了一个实现了Future
// trait的结构体IOMultiplexFuture，
// 其中定义了一个poll方法用于异步地处理多路复用的IO事件。
// 让我们分析一下这段代码的调用逻辑： 首先，当调用者调用poll方法时，
// 会传入一个可变引用self和一个任务上下文cx。
// 在方法内部，首先克隆任务上下文中的waker，并初始化一个计数器cnt为0。
// 使用unsafe块获取可变引用self，并遍历fds数组中的每个文件描述符fd。
// 对于每个文件描述符，尝试从当前进程的文件描述符表中获取对应的文件，
// 如果成功则继续处理，否则记录警告并继续下一个文件描述符的处理。
// 检查文件描述符的事件类型，如果包含POLLIN事件，调用文件的pollin方法进行处理，
// 如果返回值为Some(true)，表示有数据可读，则设置相应的标志位并增加计数器cnt。
// 类似地，如果事件类型包含POLLOUT事件，调用文件的pollout方法进行处理，
// 如果返回值为Some(true)，表示可以写入数据，则设置相应的标志位并增加计数器cnt。
// 如果处理了至少一个事件，则根据user_format字段的值更新用户提供的数据结构，
// 将处理完的文件描述符信息复制到用户空间，
// 并返回Poll::Ready(Ok(cnt))表示处理了一定数量的事件。 如果没有处理任何事件，
// 则返回Poll::Pending表示继续等待事件发生。 总的来说，这段代码的调用逻辑是：
// 遍历文件描述符数组，处理每个文件描述符的事件，
// 并根据处理结果更新用户提供的数据结构，
// 最终返回处理的事件数量或继续等待的状态。
// 这段代码主要用于异步处理多路复用的IO事件，
// 根据事件的发生情况更新文件描述符的状态，并通知调用者。
impl Future for IOMulFuture {
    type Output = Result;
    fn poll(
        self: core::pin::Pin<&mut Self>,
        cx: &mut core::task::Context<'_>,
    ) -> core::task::Poll<Self::Output> {
        // if current_task().is_zombie() {
        //     return Poll::Ready(Ok(0));
        // }
        info!("[IOMultiplexFuture::poll] enter");
        let waker = cx.waker().clone();
        let mut cnt = 0;
        let this = unsafe { self.get_unchecked_mut() };
        for fd in this.fds.iter_mut() {
            let fd_table = take_current_task().fd_table.lock();
            // info!("get fd_table");
            if let Some(file) = fd_table.get(fd.fd as usize) {
                if let Some(events) = PollEvent::from_bits(fd.events as u16) {
                    fd.revents = 0;
                    if events.contains(PollEvent::POLLIN) {
                        info!("[IOMultiplexFuture::poll] pollin fd {}", fd.fd);
                        if let Some(res) = file.pollin(Some(waker.clone())).ok() {
                            if res {
                                fd.revents |= PollEvent::POLLIN.bits() as i16;
                                cnt += 1;
                            }
                        } else {
                            fd.revents |= PollEvent::POLLERR.bits() as i16;
                            cnt += 1;
                        }
                    }
                    if events.contains(PollEvent::POLLOUT) {
                        info!("[IOMultiplexFuture::poll] pollout fd {}", fd.fd);
                        if let Some(res) = file.pollout(Some(waker.clone())).ok() {
                            if res {
                                fd.revents |= PollEvent::POLLOUT.bits() as i16;
                                cnt += 1;
                            }
                        } else {
                            fd.revents |= PollEvent::POLLERR.bits() as i16;
                            cnt += 1;
                        }
                    }
                } else {
                    info!("Invalid events: {:#x}", fd.events);
                    // TODO: not sure
                    return Poll::Ready(Err(Errno::EINVAL));
                }
            } else {
                info!("No such file for fd {}", fd.fd);
                continue;
            }
            // drop(fd_table);
        }
        if cnt > 0 {
            info!("[IOMultiplexFuture]: poll ready, cnt {}", cnt);
            // TODO: can we use user addr directly without copy overhead
            match &mut this.user_format {
                IOMulFormat::PollFds(poll_fd_ptr) => {
                    check_const_slice(*poll_fd_ptr as *const u8, this.fds.len());
                    let raw_fds: &mut [PollFd] = unsafe {
                        core::slice::from_raw_parts_mut(*poll_fd_ptr as *mut PollFd, this.fds.len())
                    };
                    raw_fds.copy_from_slice(&this.fds);
                }
                IOMulFormat::FdSets(fd_set_rwe) => {
                    fd_set_rwe.update_by_fds_vec(&this.fds);
                }
            }
            Poll::Ready(Ok(cnt))
        } else {
            info!("[IOMultiplexFuture]: no event happens");
            // cx.waker().wake_by_ref();
            Poll::Pending
        }
    }
}

use bitflags::bitflags;

#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct PollFd {
    /// Fd
    pub fd: i32,
    /// Requested events
    pub events: i16,
    /// Returned events
    pub revents: i16,
}

bitflags! {
    /// 可以被轮询的事件类型。
    ///
    /// 这些位可以在 `events` 中设置（参见 `ppoll()`）以指示感兴趣的事件类型；
    ///
    /// 它们将出现在 `revents` 中以指示文件描述符的状态。
    pub struct PollEvent: u16 {
        /// 有数据可读。
        const POLLIN = 0x001;
        /// 表示有紧急的数据可读，比如TCP socket的带外数据。。
        const POLLPRI = 0x002;
        /// 现在写入不会阻塞。
        const POLLOUT = 0x004;
        /// 表示发生了错误条件。。仅隐式轮询。总是隐式轮询的事件类型。这些位不需要在 `events` 中设置，但它们会出现在 `revents` 中以指示文件描述符的状态。
        const POLLERR = 0x008;
        /// 表示连接被挂断。仅隐式轮询。
        const POLLHUP = 0x010;
        /// 无效的轮询请求,表示文件描述符不是一个打开的文件。仅隐式轮询。
        const POLLNVAL = 0x020;
        // 这些值在 XPG4.2 中定义。
        /// 可以读取普通数据。
        const POLLRDNORM = 0x040;
        /// 可以读取优先级数据。
        const POLLRDBAND = 0x080;
        /// 现在写入不会阻塞。
        const POLLWRNORM = 0x100;
        /// 可以写入优先级数据。
        const POLLWRBAND = 0x200;
        /// Linux 扩展。
        const POLLMSG = 0x400;
        /// Linux 扩展。
        const POLLREMOVE = 0x1000;
        /// Linux 扩展。
        const POLLRDHUP = 0x2000;
    }
}

