/// 取得当前 `mtime` 计数器的值
///
/// - `mtime`: 统计处理器自上电以来经过了多少个内置时钟的时钟周期,64bit
pub fn get_time() -> usize {
    time::read()
}

pub fn get_time_ns() -> usize {
    (get_time() / (CLOCK_FREQ / USEC_PER_SEC)) * MSEC_PER_SEC
}

/// 获取CPU上电时间(单位: ms)
pub fn get_time_ms() -> usize {
    get_time() / (CLOCK_FREQ / MSEC_PER_SEC)
}

pub fn get_time_us() -> usize {
    get_time() / (CLOCK_FREQ / USEC_PER_SEC)
}

pub fn get_time_s() -> usize {
    get_time() / CLOCK_FREQ
}

/// 获取 `TimeVal` 格式的时间信息
pub fn get_timeval() -> TimeVal {
    let ticks = get_time();
    let sec = ticks / CLOCK_FREQ;
    let usec = (ticks % CLOCK_FREQ) * USEC_PER_SEC / CLOCK_FREQ;
    TimeVal { sec, usec }
}

/// Setup the next time interrupt time.
pub fn set_next_trigger() {
    set_timer((get_time() + CLOCK_FREQ / TIME_SLICE) as u64);
}

pub fn get_time_duration() -> Duration {
    Duration::from_micros(get_time_us() as u64)
}

/// 检查时钟中断是否被屏蔽
pub fn check_timer_interrupt_pending() {
    let sip = riscv::register::sip::read();
    if sip.stimer() {
        debug!("timer interrupt pending");
        set_next_trigger();
    }
    let sie = riscv::register::sie::read();
    if !sie.stimer() {
        panic!("[check_timer_interrupt_pending] timer interrupt not enable");
    }
}

