pub static KERNEL_VMM: Once<MemorySet> = Once::new();

pub fn init_kernel_vmm() {
    let mut memory_set = MemorySet::new_bare();
    macro_rules! insert_kernel_vm_areas {
        ($kvmm:ident,$($start:expr, $end:expr, $permission:expr, $file:expr, $page_offset:expr)*) => {
            $(
                $kvmm.insert(
                    VmArea::new(
                        ($start as usize).into(),
                        ($end as usize).into(),
                        MapType::Direct,
                        VmAreaType::KernelSpace,
                        $permission,
                        $file,
                        $page_offset,
                    ),
                    None
                );
            )*
        };
    }
    insert_kernel_vm_areas! { memory_set,
        stext,       ssignal,        MapPermission::R | MapPermission::X, None, 0
        ssignal,     esignal,        MapPermission::R | MapPermission::X | MapPermission::U, None, 0
        esignal,     etext,          MapPermission::R | MapPermission::X, None, 0
        srodata,     erodata,        MapPermission::R, None, 0
        sdata,       edata,          MapPermission::R | MapPermission::W, None, 0
        sbss,        ebss,           MapPermission::R | MapPermission::W, None, 0
        ekernel,     VIRT_ADDR_END,  MapPermission::R | MapPermission::W, None, 0
    }

    info!(
        "[kernel].text [{:#x}, {:#x}) [{:#x}, {:#x})",
        stext as usize, ssignal as usize, esignal as usize, etext as usize
    );
    info!(
        "[kernel].text.trampoline [{:#x}, {:#x})",
        ssignal as usize, esignal as usize,
    );
    info!("[kernel] user_sigreturn [{:#x})", user_sigreturn as usize);
    info!(
        "[kernel].rodata [{:#x}, {:#x})",
        srodata as usize, erodata as usize
    );
    info!(
        "[kernel].data [{:#x}, {:#x})",
        sdata as usize, edata as usize
    );
    info!(
        "[kernel].stack [{:#x}, {:#x})",
        skstack0 as usize, ekstack0 as usize
    );
    info!("[kernel].bss [{:#x}, {:#x})", sbss as usize, ebss as usize);
    info!(
        "[kernel]physical mem [{:#x}, {:#x})",
        ekernel as usize, VIRT_ADDR_END as usize
    );

    // For MMIO(Memory mapped IO).
    for &pair in MMIO {
        insert_kernel_vm_areas!(
            memory_set,
            pair.0 + VIRT_ADDR_OFFSET,
            pair.0 + pair.1 + VIRT_ADDR_OFFSET,
            MapPermission::R | MapPermission::W,
            None,
            0
        );
    }
    KERNEL_VMM.call_once(|| memory_set);
}
