impl Syscall<'_> {
    // #define SYS_clone 220
    pub fn sys_do_fork(
        &self,
        flags: usize,
        stack: usize,
        ptid: usize,
        tls: usize,
        ctid: usize,
    ) -> Result {
        trace!(
            "[sys_do_fork] flags:{:x} stack:{:?} ptid {:?} tls {:?} ctid {:?}",
            flags,
            stack,
            ptid,
            tls,
            ctid
        );
        // let sig = flags & 0xff;
        let flags = CloneFlags::from_bits(flags & !0xff).unwrap();
        let current_task = self.task;
        info!(
            "[sys_do_fork] flags:{:?} stack:{:x} ptid {:x} tls {:x} ctid {:x}",
            flags, stack, ptid, tls, ctid
        );
        // let new_task = if flags.contains(CloneFlags::THREAD) {
        //     current_task.thread_fork(flags)
        // } else {
        //     current_task.process_fork(flags)}
        let new_task = match flags.contains(CloneFlags::THREAD) {
            true => current_task.thread_fork(flags),
            false => current_task.process_fork(flags),
        };
        let trap_cx = new_task.trap_context_mut();
        let new_taskid = new_task.get_taskid();

        if stack != 0 {
            trap_cx.set_sp(stack);
        }
        if flags.contains(CloneFlags::PARENT_SETTID) {
            check_mut_slice(ptid as *mut u8, core::mem::size_of::<usize>());
            unsafe {
                *(ptid as *mut usize) = new_taskid;
            }
        }
        if flags.contains(CloneFlags::CHILD_SETTID) {
            check_mut_slice(ctid as *mut u8, core::mem::size_of::<usize>());
            // new_task.set_tid_address(ctid);
            unsafe {
                *(ctid as *mut usize) = new_taskid;
            }
        }
        if flags.contains(CloneFlags::CHILD_CLEARTID) {
            new_task.set_clear_tid_address(ctid);
        }
        if flags.contains(CloneFlags::SETTLS) {
            trap_cx.set_tp(tls);
        }
        // new_task.set_exitsignal(sig as u8);
        TASK_MANAGER.add(&new_task);
        trap_cx.set_a0(0);
        spawn_utask(new_task);
        Ok(new_taskid as isize)
    }

    /// #define SYS_execve 221

    pub async fn sys_exec(&self, path: usize, argv: usize, envp: usize) -> Result {
        info!(
