            path, argv, envp
        );
        // let task = self.task;
        // task.check_lazy(argv.into());
        // task.check_lazy(envp.into());
        let path = path as *const u8;
        let argv = argv as *const *const u8;
        let envp = envp as *const *const u8;

        let mut path = translated_str(path);
        let mut args_vec: Vec<String> = Vec::new();
        let mut envs_vec: Vec<String> = Vec::new();
        if path.contains(".sh") {
            // if path.contains("iozone") {
            //     #[cfg(feature = "multi-harts")]
            //     wake_other_harts_hsm();
            // }
            path = "busybox".to_string();
            args_vec.push("busybox".to_string());
            args_vec.push("sh".to_string());
        } else if path.ends_with("ls") || path.ends_with("sleep") {
            path = "/busybox".to_string();
            args_vec.push("busybox".to_string());
        }
        if path.contains("ltp") {
            unsafe {
                IS_LTP = 1;
            }
        } else {
            unsafe {
                IS_LTP = 0;
            }
        }
        let task = self.task;
        let inner = task.pcb();
        _ = check_and_clone_cstr_array(&mut args_vec, argv)?;
        _ = check_and_clone_cstr_array(&mut envs_vec, envp)?;

        envs_vec.push("PATH=/".to_string());
        envs_vec.push("LD_LIBRARY_PATH=/".to_string());
        let new_path = inner.current_path.clone().cd(path);
        let app_inode = open(new_path.clone(), OpenFlags::O_RDONLY, CreateMode::empty())?;
        if app_inode.file_size() < 64 {
            return_errno!(Errno::ENOEXEC);
        }
        drop(inner);
        task.exec(app_inode, args_vec, envs_vec).await;
        Ok(0 as isize)
    }

