use config::PAGE_SIZE;
use kmem::{
    address::{VPNRange, VirtAddr},
    page_table::{PTEFlags, PageTable},
    permission::MapPermission,
};
use log::{info, trace};
use nix::{MmapFlags, MmapProts, IPC_PRIVATE, IPC_RMID};
use riscv::asm::{sfence_vma, sfence_vma_all};
use utils::errno::{Errno, Result};

use crate::{
    ipc::shm::{create_shm, remove_shm}, return_errno, syscall::Syscall, task::processor::{current_user_token, take_current_task}
};

impl Syscall<'_> {
    // #define SYS_brk 214
    pub fn sys_brk(&self, brk: usize) -> Result {
        let task = self.task;
        if brk == 0 {
            Ok(task.grow_proc(0) as isize)
        } else {
            let former_addr = task.grow_proc(0);
            let grow_size: isize = (brk - former_addr) as isize;
            Ok(self.task.grow_proc(grow_size) as isize)
        }
    }

    // #define SYS_munmap 215
    pub fn sys_munmap(&self, addr: usize, length: usize) -> Result {
        let task = self.task;
        Ok(task.munmap(addr, length))
    }

    // #define SYS_mmap 222
    pub fn sys_mmap(
        &self,
        addr: usize,
        length: usize,
        prot: usize,
        flags: usize,
        fd: isize,
        offset: usize,
    ) -> Result {
        let mut padding = PAGE_SIZE - length % PAGE_SIZE;
        if padding == PAGE_SIZE {
            padding = 0;
        }
        let length = length + padding;
        let task = self.task;
        let fd_table = task.fd_table.lock();
        let prot = MmapProts::from_bits(prot).expect("unsupported mmap prot");
        let flags = MmapFlags::from_bits(flags).expect("unsupported mmap flags");
        info!(
        "[sys_mmap]: start...  addr {:#x}, len {:#x}, fd {}, offset {:#x}, flags {:?}, prot {:?}",
        addr, length, fd, offset, flags, prot
    );
        // flags.remove(MmapFlags::MAP_PRIVATE);
        // flags |= MmapFlags::MAP_SHARED;
        if length == 0 {
            return Err(Errno::EINVAL);
        }
        if !flags.contains(MmapFlags::MAP_ANONYMOUS)
            && (fd as usize >= fd_table.table.len() || fd_table.table[fd as usize].is_none())
        {
            return Err(Errno::EBADF);
        }
        drop(fd_table);

        let result_addr = task.mmap(addr, length, prot, flags, fd, offset);

        Ok(result_addr as isize)
    }

    // shmget 194
    pub fn sys_shmget(&self, key: usize, size: usize, shmflg: usize) -> Result {
        info!("create shm");
        let size = (size + PAGE_SIZE - 1) / PAGE_SIZE * PAGE_SIZE;
        assert!(size % PAGE_SIZE == 0);
        let new_key;
        let pid = self.task.get_taskid();
        if key == IPC_PRIVATE {
            new_key = create_shm(key, size, shmflg);
        } else {
            unimplemented!();
        }
        Ok(new_key as isize)
    }

    // shmctl 195
    pub fn sys_shmctl(&self, key: usize, cmd: usize, _buf: *const u8) -> Result {
        info!("remove shm");
        if cmd == IPC_RMID {
            remove_shm(key);
        } else {
            unimplemented!();
        }
        Ok(0)
    }

    // shmat 196
    pub fn sys_shmat(&self, key: usize, address: usize, _shmflg: usize) -> Result {
        info!("attach shm key {:?} shm address {:#x}", key, address);
        let task = self.task;
        let mut memory_set = task.memory_set.lock();
        let address = if address == 0 {
            memory_set.shm_top
        } else {
            address
        };
        memory_set.attach_shm(key, address.into());
        drop(memory_set);
        Ok(address as isize)
    }

    // shmdt 197
    pub fn sys_shmdt(&self, address: usize) -> Result {
        info!("detach shm address {:#x}", address);
        let task = self.task;
        let mut memory_set = task.memory_set.lock();
        let nattch = memory_set.detach_shm(address.into());
        drop(memory_set);
        // detach_shm called when drop SharedMemoryTracker

        Ok(nattch as isize)
    }

    // mprotect 226
    pub fn sys_mprotect(&self, addr: usize, length: usize, prot: usize) -> Result {
        trace!("sys_mprotect addr {:x}", addr);
        let token = current_user_token();
        let page_table = PageTable::from_token(token);

        let map_flags = (((prot & 0b111) << 1) + (1 << 4)) as u16;
        let map_perm = MapPermission::from_bits(map_flags).unwrap();
        let pte_flags = PTEFlags::from_bits(map_perm.bits()).unwrap();

        let start_va = VirtAddr::from(addr);
        let end_va = VirtAddr::from(addr + length);
        let vpn_range = VPNRange::from_va(start_va, end_va);

        for vpn in vpn_range {
            if let Some(pte) = page_table.find_pte(vpn) {
                pte.set_flags(pte.flags().union(pte_flags));
            } else {
                let task = self.task;
                let mut memory_set = task.memory_set.lock();
                let mmap_start = memory_set.mmap_manager.mmap_start;
                let mmap_top = memory_set.mmap_manager.mmap_top;
                let mmap_perm = MmapProts::from_bits(prot).unwrap();
                let va: VirtAddr = vpn.into();
                if va >= mmap_start && va < mmap_top {
                    memory_set
                        .mmap_manager
                        .mmap_map
                        .get_mut(&vpn)
                        .unwrap()
                        .set_prot(mmap_perm);
                    continue;
                }
                let va: VirtAddr = vpn.into();
                return_errno!(Errno::EINVAL, "invalid address: {:?}", va);
            }
        }
        Ok(0)
    }
}

