    // sigaction 134
    pub fn sys_sigaction(
        &self,
        signum: isize,
        act: *const SigAction,
        oldact: *mut SigAction,
    ) -> Result {
        info!(
            "[sys_sigaction]: signum {}, new act ptr {:#x}, old act ptr {:#x}, act size {}",
            signum,
            act as usize,
            oldact as usize,
            core::mem::size_of::<SigAction>()
        );
        let task = self.task;
        let signum = signum as i32;

        // signum 超出范围, 返回错误
        if signum > MAX_SIGNUM as i32
            || signum == Signal::SIGKILL as i32
            || signum == Signal::SIGSTOP as i32
        {
            return Err(Errno::EINVAL);
        }
        if oldact as usize != 0 {
            let sigactions = task.sigactions.lock();
            let old_action = sigactions.get(signum as usize).unwrap();
            unsafe {
                match old_action.sa_type {
                    SaHandlerType::Customized { handler } => {
                        oldact.copy_from(&old_action.sig_action as *const SigAction, 1);
                    }
                    _ => {
                        let mut action = old_action.sig_action;
                        action.sa_handler = SIG_DFL;
                        oldact.copy_from(&action as *const SigAction, 1);
                    }
                }
                // oldact.copy_from(&old_action.sig_action as *const SigAction, 1);
                info!("[sys_sigaction]: sig {}, get old sig handler {:#x}, sa_mask {:#x}, sa_flags: {:#x}", signum, (*oldact).sa_handler as *const usize as usize, (*oldact).sa_mask, (*oldact).sa_flags);
            }
        }
        // 当 sigaction 存在时,  在 pcb 中注册给定的 signaction
        if act as usize != 0 {
            let mut sigaction = unsafe { *act };

            let new_sigaction = match sigaction.sa_handler {
                SIG_DFL => KSigAction::new(Signal::from(signum as i32)),
                SIG_IGN => {
                    let actype = SaHandlerType::Ignore;
                    sigaction.sa_handler = SIG_DFL;
                    KSigAction {
                        sa_type: actype,
                        sig_action: sigaction,
                    }
                }
                handler => {
                    let actype = SaHandlerType::Customized { handler };
                    KSigAction {
                        sa_type: actype,
                        sig_action: sigaction,
                    }
                }
            };
            // if println will block on
            // trace!(
            //     "[sys_sigaction]: sig {}, set new sig handler {:#x}, sa_mask {:?},
            // sa_flags: {:#x}, sa_restorer: {:#x}",     signum,
            // new_sigaction.sig_action.sa_handler as *const usize as usize,
            // new_sigaction.sig_action.sa_mask, new_sigaction.sig_action.sa_flags,
            // new_sigaction.sig_action.sa_restorer, );
            // warning
            // task.set_sigaction(signum as usize, new_sigaction);
            task.sigactions
                .lock()
                .set_sigaction(signum as usize, new_sigaction);
        }

        Ok(0)
    }

