    pub fn sys_sigprocmask(
        &self,
        how: usize,
        set: *const usize,
        old_set: *mut SigSet,
        _sigsetsize: usize,
    ) -> Result {
        info!(
            "[sys_sigprocmask] how {} set {:#x}, old_set {:#x}, sigsetsize {}",
            how,
            unsafe { *set },
            old_set as usize,
            _sigsetsize
        );
        let task = self.task;
        if old_set as usize != 0 {
            unsafe {
                *old_set = *task.sig_mask();
            }
        }
        if set as usize != 0 {
            let new_set = unsafe { SigMask::from_bits(*set as usize).ok_or(Errno::EINVAL)? };

            // trace!(
            //     "[sys_sigprocmask](how {} new_set: {:?},old_set: {:?})",
            //     how, new_set, old_set
            // );
            let how = MaskFlags::from_how(how);
            match how {
